import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
all_keys = sorted(set(list(b.keys()) + list(a.keys())))
for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k, '-')
    av = a.get(k, '-')
    if bv != av:
        if bv == '-': status = 'Added'
        elif av == '-': status = 'Removed'
        else: status = f'Aligned to highest version'
        changes.append((proj, fw, pkg, bv, av, status))
    else:
        unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]} [{c[5]}]')
else:
    print('None')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} ({u[1]}): {u[2]} = {u[3]}')
"

