for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k, '-')
    av = a.get(k, '-')
    if bv != av:
        if bv == '-':
            status = 'Added'
        elif av == '-':
            status = 'Removed'
        else:
            status = 'Aligned to highest version'
        changes.append((proj, fw, pkg, bv, av, status))
    else:
        unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}): {c[2]}  {c[3]} -> {c[4]}  [{c[5]}]')
else:
    print('  None')

print()
print(f'=== UNCHANGED ({len(unchanged)} entries) ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}): {u[2]} = {u[3]}')
